export function getProductsByType(type: ProductType): Product[] {
  return products.filter((p) => p.type === type);
}

export function getProductById(id: string): Product | undefined {
  return products.find((p) => p.id === id);
}

export type AmountRangeId =
  | 'under-500'
  | '500-2000'
  | '2000-10000'
  | '10000-50000'
  | '50000-plus';

export type DemoTab = 'cards' | 'telecom' | 'insurance';

export type RewardSuggestion = {
  rank: number;
  name: string;
  paymentType: 'Credit Card' | 'Debit Card' | 'UPI';
  rate: string;
  ratePercent: number;
  howTo: string;
  brandColor: string;
  network: string;
  estimatedReward: number;
};

