export function getProductsForDemoTab(tab: DemoTab): Product[] {
  switch (tab) {
    case 'cards':
      return products.filter((p) => p.type === 'credit-card' || p.type === 'debit-card');
    case 'telecom':
      return products.filter((p) => p.type === 'telecom');
    case 'insurance':
      return products.filter(
        (p) =>
          p.type === 'health-insurance' ||
          p.type === 'motor-insurance' ||
          p.type === 'term-insurance',
      );
  }
}

const CATEGORY_LABELS: Record<BenefitCategory, string> = {
  lounge: '✈ LOUNGE',
  insurance: '🛡 COVER',
  cashback: '💰 CASHBACK',
  ott: '🎬 OTT',
  discount: '🏷 DISCOUNT',
  health: '🩺 HEALTH',
  golf: '⛳ GOLF',
  fuel: '⛽ FUEL',
  dining: '🍽 DINING',
  travel: '✈ TRAVEL',
  other: '📌 OTHER',
};

const RESET_SUBLABELS: Record<ResetPeriod, string> = {
  month: 'resets monthly',
  quarter: 'resets quarterly',
  year: 'resets yearly',
  once: 'one-time benefit',
  'per-recharge': 'per recharge cycle',
};

export function getProductMeta(p: Product): string {
  const fee =
    p.annualFee === 0
      ? 'lifetime free'
      : p.annualFee != null
        ? `₹${p.annualFee.toLocaleString('en-IN')} fee`
        : null;
  const parts = [p.issuer, `${p.benefits.length} benefit${p.benefits.length === 1 ? '' : 's'}`];
  if (fee) parts.splice(1, 0, fee);
  return parts.join(' · ');
}

export function benefitToDisplay(b: Benefit): {
  cat: string;
  title: string;
  sub: string;
  val: string;
  color: string;
} {
  let val: string;
  if (b.quota === null) {
    val = b.category === 'insurance' || b.value === '✓' ? '✓' : '∞';
  } else {
    val = `${b.quota}/${b.quota}`;
  }
  return {
    cat: CATEGORY_LABELS[b.category],
    title: b.title,
    sub: RESET_SUBLABELS[b.resetPeriod],
    val,
    color: b.accentColor,
  };
}

const AMOUNT_MIDPOINTS: Record<AmountRangeId, number> = {
  'under-500': 300,
  '500-2000': 1250,
  '2000-10000': 6000,
  '10000-50000': 30000,
  '50000-plus': 75000,
};

export function parseRatePercent(rate: string): number {
  const range = rate.match(/(\d+(?:\.\d+)?)\s*[–-]\s*(\d+(?:\.\d+)?)\s*%/);
  if (range) return (parseFloat(range[1]) + parseFloat(range[2])) / 2;

  const slashPct = rate.match(/\(~(\d+(?:\.\d+)?)%\)/);
  if (slashPct) return parseFloat(slashPct[1]);

  const pct = rate.match(/(\d+(?:\.\d+)?)\s*%/);
  if (pct) return parseFloat(pct[1]);

  const miles = rate.match(/(\d+(?:\.\d+)?)\s*(?:EDGE Miles|CV Points|RP|MR|points?)\s*\/\s*₹?\s*(\d+)/i);
  if (miles) {
    const num = parseFloat(miles[1]);
    const denom = parseFloat(miles[2]);
    return (num / denom) * 100;
  }

  const multiplier = rate.match(/(\d+(?:\.\d+)?)X/i);
  if (multiplier) return parseFloat(multiplier[1]) * 0.5;

  return 1;
}

function categoryLookupKey(txType: string, category: string): string {
  return `${txType}:${category}`;
}

function productMatchesTx(
  product: Product,
  txType: string,
  category: string,
): boolean {
  const rl = product.rewardLogic;
  if (!rl) return false;
  const key = categoryLookupKey(txType, category);
  const cats = rl.categories;
  if (cats.includes(key)) return true;
  if (cats.includes(txType)) return true;
  if (cats.includes(category)) return true;
  if (txType === 'fuel' && cats.includes('fuel')) return true;
  return cats.some(
    (c) =>
      c === `online:${category}` ||
      c === `offline:${category}` ||
      c === `dining:${category}` ||
      c === `travel:${category}` ||
      c === `pharmacy:${category}` ||
      c === `hospital:${category}` ||
      c.endsWith(`:${category}`),
  );
}

export function getEffectiveRewardRate(
  product: Product,
  txType: string,
  category?: string,
): { rate: string; percent: number } {
  const rl = product.rewardLogic;
  if (!rl) return { rate: '0%', percent: 0 };

  const key = category ? categoryLookupKey(txType, category) : txType;

  if (key.includes('amazon') && rl.onlineBonusRate) {
    const p = parseRatePercent(rl.onlineBonusRate);
    return { rate: rl.onlineBonusRate, percent: p };
  }
  if (key.includes('flipkart') && rl.onlineBonusRate) {
    return { rate: rl.onlineBonusRate, percent: parseRatePercent(rl.onlineBonusRate) };
  }
  if (
    (key.includes('swiggy') || key.includes('food-delivery') || category === 'food-delivery') &&
    rl.diningRate
  ) {
    return { rate: rl.diningRate, percent: parseRatePercent(rl.diningRate) };
  }
  if (txType === 'fuel' && rl.fuelRate) {
    return { rate: rl.fuelRate, percent: parseRatePercent(rl.fuelRate) };
  }
  if (txType === 'dining' && rl.diningRate) {
    return { rate: rl.diningRate, percent: parseRatePercent(rl.diningRate) };
  }
  if (txType === 'travel' && rl.travelRate) {
    return { rate: rl.travelRate, percent: parseRatePercent(rl.travelRate) };
  }
  if (category === 'grocery' && rl.groceryRate) {
    return { rate: rl.groceryRate, percent: parseRatePercent(rl.groceryRate) };
  }
  if (txType === 'online' && rl.onlineBonusRate) {
    return { rate: rl.onlineBonusRate, percent: parseRatePercent(rl.onlineBonusRate) };
  }
  if (txType === 'offline' && rl.offlineBonusRate) {
    return { rate: rl.offlineBonusRate, percent: parseRatePercent(rl.offlineBonusRate) };
  }

  return { rate: rl.rewardRate, percent: parseRatePercent(rl.rewardRate) };
}

export function getRewardProducts(audience: 'personal' | 'business'): Product[] {
  return products.filter((p) => {
    if (!p.rewardLogic) return false;
    const isBusiness = p.rewardLogic.categories.includes('business');
    if (audience === 'business') return isBusiness;
    return p.type === 'upi' || !isBusiness;
  });
}

function paymentTypeLabel(
  type: ProductType,
): 'Credit Card' | 'Debit Card' | 'UPI' {
  if (type === 'credit-card') return 'Credit Card';
  if (type === 'debit-card') return 'Debit Card';
  return 'UPI';
}

function defaultNetwork(product: Product): string {
  if (product.network) return product.network;
  if (product.type === 'upi') return 'Rupay';
  return 'Visa';
}

export function getRewardSuggestions(
  txType: string,
  category: string,
  amountRange: AmountRangeId,
  audience: 'personal' | 'business',
  limit = 3,
): RewardSuggestion[] {
  const midpoint = AMOUNT_MIDPOINTS[amountRange];
  const candidates = getRewardProducts(audience).filter((p) =>
    productMatchesTx(p, txType, category),
  );

  const scored = candidates
    .map((p) => {
      const { rate, percent } = getEffectiveRewardRate(p, txType, category);
      const topBenefit = p.benefits.find((b) => b.category === 'cashback') ?? p.benefits[0];
      return {
        name: p.name,
        paymentType: paymentTypeLabel(p.type),
        rate,
        ratePercent: percent,
        howTo: topBenefit?.howToClaim ?? `Use ${p.name} for this transaction.`,
        brandColor: ISSUER_COLORS[p.issuer] ?? '#6B7280',
        network: defaultNetwork(p),
        estimatedReward: Math.round((midpoint * percent) / 100),
      };
    })
    .sort((a, b) => b.ratePercent - a.ratePercent);

  return scored.slice(0, limit).map((entry, index) => ({
    ...entry,
    rank: index + 1,
  }));
}
